DataSource.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type;
INSERT INTO @PermissionIDs VALUES ('ITSMSpecialist'), ('ITSMOperator');

SELECT TOP(1)
    itsGagvftap.GroupID
FROM usr.ITSM_GetAllowedGroupByFolderTreeAndPermission(
    COALESCE(@ITSMCategoryLevel5Ident, @ITSMCategoryLevel4Ident, @ITSMCategoryLevel3Ident, @ITSMCategoryLevel2Ident, @ITSMCompanyIdent),
    @PermissionIDs
) AS itsGagvftap
INNER JOIN dbo.GroupAccount AS gra ON gra.GroupID = itsGagvftap.GroupID AND gra.AccountID = @UserID

IF @ITSMKey IS NULL
BEGIN
  DECLARE
    @CounterIdent VARCHAR(100) = 'ITSM_{{KeyPrefix}}',
    @NextNumber INT

  EXEC @NextNumber = usr.CounterGetNext @CounterIdent, @UserID;

  UPDATE usr.[ITSMChange]
  SET ITSMKey = CONCAT('{{KeyPrefix}}-', RIGHT('000000' + CAST(@NextNumber AS VARCHAR(6)), 6))
  WHERE ID = @ID
END

DECLARE @ITSMKey VARCHAR(100) = (
  SELECT ITSMKey
  FROM usr.ITSMChange
  WHERE ID = @ID
)
DECLARE
  @CounterIdent VARCHAR(100) = CONCAT(@ITSMKey, '_P'),
  @NextNumber INT

EXEC @NextNumber = usr.CounterGetNext @CounterIdent, @UserID;

UPDATE usr.ITSMAssessment
SET AssessmentRoundStartDateTime = GETDATE(),ITSMKey = CONCAT(@ITSMKey, '_P:', @NextNumber)
WHERE AssessmentRoundGUID = @ActualAssessmentRoundGuid

Condition.SQL:
DECLARE @PermissionIDs dbo.ListNVarchar100Type; INSERT INTO @PermissionIDs VALUES ('ITSMOperator');
DECLARE @LastITSMCategoryIdent VARCHAR(900) = @ITSMCategoryLevel2Ident; IF @IsShowCategoryLevel3 = 1 SET @LastITSMCategoryIdent = @ITSMCategoryLevel3Ident IF @IsShowCategoryLevel4 = 1 SET @LastITSMCategoryIdent = @ITSMCategoryLevel4Ident IF @IsShowCategoryLevel5 = 1 SET @LastITSMCategoryIdent = @ITSMCategoryLevel5Ident
SELECT IIF( EXISTS( SELECT NULL FROM usr.ITSM_GetAllowedFolderTreeByAccountAndPermissionAndSegmentType(@UserID,@FolderGroupSegmentIdent,'ITSMChangeSegment',@PermissionIDs) WHERE FolderTreeIdent = @LastITSMCategoryIdent ) OR ISNULL(@ID, 0) != 0 , 0, 1)
